r_hchora_rep_mem_share_loan_year_nest_em.sql:
SELECT sc_lon_m_rule.loan_type ,(CASE sc_lon_m_ucf_loan_code.loan_code WHEN '0' THEN sc_lon_m_rule.loan_type_description ELSE sc_lon_m_ucf_loan_code.loan_code_desc || ' ' || sc_lon_m_rule.loan_type_description END) as loan_type_description , sum( sc_rep_mem_share_loan_bal.emer_balance ) as loan_balance FROM sc_rep_mem_share_loan_bal, sc_lon_m_ucf_loan_code, sc_lon_m_rule, sc_mem_m_ucf_member_group WHERE ( sc_rep_mem_share_loan_bal.emer_loan_code = sc_lon_m_ucf_loan_code.loan_code ) and ( sc_rep_mem_share_loan_bal.emer_loantype = sc_lon_m_rule.loan_type ) and ( sc_rep_mem_share_loan_bal.member_group_no = sc_mem_m_ucf_member_group.member_group_no ) and ( sc_rep_mem_share_loan_bal.emer_balance > 0 )
/*WHERE*/ and sc_rep_mem_share_loan_bal.balance_date = {0} and sc_lon_m_rule.loan_group_code = '01'
GROUP BY sc_lon_m_rule.loan_type, sc_lon_m_rule.loan_type_description, sc_lon_m_ucf_loan_code.loan_code, sc_lon_m_ucf_loan_code.loan_code_desc order by sc_lon_m_ucf_loan_code.loan_code , sc_lon_m_rule.loan_type

